    22→  /** Link to privacy policy */
    23→  privacyPolicyUrl?: string;
    24→  /** Custom consent message */
    25→  customMessage?: string;
    26→}
    27→
    28→export interface ConsentResult {
    29→  /** Whether consent was granted */
    30→  granted: boolean;
    31→  /** Timestamp of consent decision */
    32→  timestamp: number;
    33→  /** Consent options that were presented */
    34→  options: ConsentOptions;
    35→  /** Participant ID if available */
    36→  participantId?: string;
    37→  /** Session ID */
    38→  sessionId: string;
    39→}
    40→
    41→export class ConsentManager {
    42→  private consentResults: Map<string, ConsentResult> = new Map();
    43→  private static instance: ConsentManager;
    44→
    45→  private constructor() {}
    46→
    47→  static getInstance(): ConsentManager {
    48→    if (!ConsentManager.instance) {
    49→      ConsentManager.instance = new ConsentManager();
    50→    }
    51→    return ConsentManager.instance;
    52→  }
    53→
    54→  /**
    55→   * Request consent from participant
    56→   */
    57→  async requestConsent(
    58→    sessionId: string,
    59→    options: ConsentOptions,
    60→    participantId?: string
    61→  ): Promise<ConsentResult> {
    62→    // Check if consent already granted for this session
    63→    const existingConsent = this.consentResults.get(sessionId);
    64→    if (existingConsent && existingConsent.granted) {
    65→      return existingConsent;
    66→    }
    67→
    68→    // Create consent UI
    69→    const consentResult = await this.showConsentDialog(options);
    70→    
    71→    // Store consent result
    72→    const result: ConsentResult = {
    73→      granted: consentResult,
    74→      timestamp: Date.now(),
    75→      options,
    76→      participantId,
    77→      sessionId,
    78→    };
    79→
    80→    this.consentResults.set(sessionId, result);
    81→    
    82→    // Log consent decision for compliance
    83→    console.log(`Consent ${result.granted ? 'granted' : 'denied'} for session ${sessionId}`, {
    84→      timestamp: new Date(result.timestamp).toISOString(),
    85→      purpose: options.purpose,
    86→      dataTypes: options.dataTypes,
    87→      participantId,
    88→    });
    89→
    90→    return result;
    91→  }
    92→
    93→  /**
    94→   * Get consent status for a session
    95→   */
    96→  getConsentStatus(sessionId: string): ConsentResult | null {
    97→    return this.consentResults.get(sessionId) || null;
    98→  }
    99→
   100→  /**
   101→   * Check if consent is granted for a session
   102→   */
   103→  hasConsent(sessionId: string): boolean {
   104→    const result = this.consentResults.get(sessionId);
   105→    return result?.granted || false;
   106→  }
   107→
   108→  /**
   109→   * Revoke consent for a session
   110→   */
   111→  revokeConsent(sessionId: string): void {
   112→    const result = this.consentResults.get(sessionId);
   113→    if (result) {
   114→      result.granted = false;
   115→      result.timestamp = Date.now();
   116→      console.log(`Consent revoked for session ${sessionId}`);
   117→    }
   118→  }
   119→
   120→  /**
   121→   * Get all consent records (for data audit purposes)
   122→   */
   123→  getAllConsentRecords(): ConsentResult[] {
   124→    return Array.from(this.consentResults.values());
   125→  }
   126→
   127→  /**
   128→   * Clear expired consent records
   129→   */
   130→  clearExpiredConsent(maxAge: number = 24 * 60 * 60 * 1000): void {
   131→    const now = Date.now();
   132→    for (const [sessionId, result] of this.consentResults.entries()) {
   133→      if (now - result.timestamp > maxAge) {
   134→        this.consentResults.delete(sessionId);
   135→      }
   136→    }
   137→  }
   138→
   139→  /**
   140→   * Show consent dialog to user
   141→   */
   142→  private async showConsentDialog(options: ConsentOptions): Promise<boolean> {
   143→    return new Promise((resolve) => {
   144→      // Create modal backdrop
   145→      const backdrop = document.createElement('div');
   146→      backdrop.style.cssText = `
   147→        position: fixed;
   148→        top: 0;
   149→        left: 0;
   150→        width: 100%;
   151→        height: 100%;
   152→        background-color: rgba(0, 0, 0, 0.5);
   153→        display: flex;
   154→        align-items: center;
   155→        justify-content: center;
   156→        z-index: 10000;
   157→        font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
   158→      `;
   159→
   160→      // Create modal dialog
   161→      const dialog = document.createElement('div');
   162→      dialog.style.cssText = `
   163→        background: white;
   164→        border-radius: 8px;
   165→        padding: 24px;
   166→        max-width: 600px;
   167→        max-height: 80vh;
   168→        overflow-y: auto;
   169→        box-shadow: 0 4px 20px rgba(0, 0, 0, 0.15);
   170→        margin: 20px;
   171→      `;
   172→
   173→      // Create content
   174→      const title = document.createElement('h2');
   175→      title.style.cssText = `
   176→        margin: 0 0 16px 0;
   177→        color: #1f2937;
   178→        font-size: 20px;
   179→        font-weight: 600;
   180→      `;
   181→      title.textContent = 'Data Collection Consent';
   182→
   183→      const message = document.createElement('div');
   184→      message.style.cssText = `
   185→        margin-bottom: 20px;
   186→        color: #374151;
   187→        line-height: 1.6;
   188→      `;
   189→      
   190→      // Sanitize the privacy policy URL to prevent XSS
   191→      const sanitizedPrivacyUrl = options.privacyPolicyUrl ? sanitizeUrl(options.privacyPolicyUrl) : null;
   192→      
   193→      const defaultMessage = `
   194→        <p><strong>Purpose:</strong> ${this.escapeHtml(options.purpose)}</p>
   195→        <p><strong>Data Types:</strong> ${options.dataTypes.map(dt => this.escapeHtml(dt)).join(', ')}</p>
   196→        ${options.storageDuration ? `<p><strong>Storage Duration:</strong> ${this.escapeHtml(options.storageDuration)}</p>` : ''}
   197→        ${options.contactInfo?.email ? `<p><strong>Contact:</strong> ${this.escapeHtml(options.contactInfo.email)}</p>` : ''}
   198→        ${sanitizedPrivacyUrl ? `<p><a href="${sanitizedPrivacyUrl}" target="_blank" rel="noopener noreferrer">View Privacy Policy</a></p>` : ''}
   199→        <p>Do you consent to this data collection?</p>
   200→      `;
   201→
   202→      message.innerHTML = options.customMessage ? this.escapeHtml(options.customMessage) : defaultMessage;
   203→
   204→      // Create buttons
   205→      const buttonContainer = document.createElement('div');
   206→      buttonContainer.style.cssText = `
   207→        display: flex;
   208→        gap: 12px;
   209→        justify-content: flex-end;
   210→        margin-top: 24px;
   211→      `;
   212→
   213→      const denyButton = document.createElement('button');
   214→      denyButton.style.cssText = `
   215→        padding: 8px 16px;
   216→        border: 1px solid #d1d5db;
   217→        background: white;
   218→        color: #374151;
   219→        border-radius: 4px;
   220→        cursor: pointer;
   221→        font-size: 14px;
   222→        font-weight: 500;
   223→      `;
   224→      denyButton.textContent = 'Deny';
   225→      denyButton.onclick = () => {
   226→        document.body.removeChild(backdrop);
   227→        resolve(false);
   228→      };
   229→
   230→      const acceptButton = document.createElement('button');
   231→      acceptButton.style.cssText = `
   232→        padding: 8px 16px;
   233→        border: none;
   234→        background: #3b82f6;
   235→        color: white;
   236→        border-radius: 4px;
   237→        cursor: pointer;
   238→        font-size: 14px;
   239→        font-weight: 500;
   240→      `;
   241→      acceptButton.textContent = 'Accept';
   242→      acceptButton.onclick = () => {
   243→        document.body.removeChild(backdrop);
   244→        resolve(true);
   245→      };
   246→
   247→      // Add hover effects
   248→      denyButton.onmouseover = () => {
   249→        denyButton.style.backgroundColor = '#f3f4f6';
   250→      };
   251→      denyButton.onmouseout = () => {
   252→        denyButton.style.backgroundColor = 'white';
   253→      };
   254→
   255→      acceptButton.onmouseover = () => {
   256→        acceptButton.style.backgroundColor = '#2563eb';
   257→      };
   258→      acceptButton.onmouseout = () => {
   259→        acceptButton.style.backgroundColor = '#3b82f6';
   260→      };
   261→
   262→      // Assemble dialog
   263→      buttonContainer.appendChild(denyButton);
   264→      buttonContainer.appendChild(acceptButton);
   265→      
   266→      dialog.appendChild(title);
   267→      dialog.appendChild(message);
   268→      dialog.appendChild(buttonContainer);
   269→      
   270→      backdrop.appendChild(dialog);
   271→      document.body.appendChild(backdrop);
   272→
   273→      // Focus accept button
   274→      acceptButton.focus();
   275→
   276→      // Handle ESC key
   277→      const handleEsc = (e: KeyboardEvent) => {
   278→        if (e.key === 'Escape') {
   279→          document.removeEventListener('keydown', handleEsc);
   280→          document.body.removeChild(backdrop);
   281→          resolve(false);
   282→        }
   283→      };
   284→      document.addEventListener('keydown', handleEsc);
