  createTextStimulus: (text: string, duration?: number) => {
    const stimulus = new TextStimulus(crypto.randomUUID(), text);
    if (duration !== undefined) {
      stimulus.duration(duration);
    }
    return stimulus;
  },

  createImageStimulus: (src: string, duration?: number) => {
    const stimulus = new ImageStimulus(crypto.randomUUID(), src);
    if (duration !== undefined) {
      stimulus.duration(duration);
    }
    return stimulus;
  },

  createAudioStimulus: (src: string, duration?: number) => {
    const stimulus = new AudioStimulus(crypto.randomUUID(), src);
    if (duration !== undefined) {
      stimulus.duration(duration);
    }
    return stimulus;
  },

  createVideoStimulus: (src: string, duration?: number) => {
    const stimulus = new VideoStimulus(crypto.randomUUID(), src);
    if (duration !== undefined) {
      stimulus.duration(duration);
    }
    return stimulus;
  },

  createKeyboardResponse: (keys?: string[], timeout?: number) => {
    const response = new KeyboardResponse(crypto.randomUUID());
    if (keys) response.keys(keys);
    if (timeout !== undefined) response.timeout(timeout);
    return response;
  },

  createMouseResponse: (timeout?: number) => {
    const response = new MouseResponse(crypto.randomUUID());
    if (timeout !== undefined) response.timeout(timeout);
    return response;
  },

  createTouchResponse: (timeout?: number) => {
    const response = new TouchResponse(crypto.randomUUID());
    if (timeout !== undefined) response.timeout(timeout);
    return response;
  },

  createWaitEvent: (duration: number) => {
    return new WaitEvent(crypto.randomUUID(), duration);
  },

  // Quick experiment runners
  runExperiment: async (experiment: Experiment, participantId?: string) => {
    return await Runtime.quickRun(experiment, participantId);
  },

  // Serialization helpers
  saveExperiment: (experiment: Experiment, options?: SerializationOptions) => {
    return Serializer.stringify(experiment, options);
  },

  loadExperiment: (jsonString: string) => {
    return Serializer.parse(jsonString);
  },

  // Validation helpers
  validateExperiment: (experiment: Experiment, options?: ValidationOptions) => {
    return Validator.validateExperiment(experiment, options);
  },

  // Runtime management
  createRuntime: async (config?: RuntimeConfiguration) => {
    return await Runtime.createAndInitialize(config);
  },

  // Common experiment patterns
  createStroop: (words: string[], colors: string[], trials: number = 20) => {
    const experiment = ForgeScript.createExperiment('Stroop Task')
      .description('Classic Stroop color-word interference task')
      .author('Generated by ForgeScript');

    // Welcome timeline
    const welcome = ForgeScript.createTimeline('welcome')
      .add(ForgeScript.createTextStimulus('Welcome to the Stroop Task!', 2000))
      .add(ForgeScript.createTextStimulus('Press SPACE to continue'))
      .add(ForgeScript.createKeyboardResponse(['space']));

    // Instructions timeline
    const instructions = ForgeScript.createTimeline('instructions')
      .add(ForgeScript.createTextStimulus(
        'Name the COLOR of each word, not the word itself.\nPress F for red, G for green, H for blue.\nPress SPACE to start.',
        5000
      ))
      .add(ForgeScript.createKeyboardResponse(['space']));

    // Trial timeline
    const trialTimeline = ForgeScript.createTimeline('trials')
      .repeat(trials)
      .randomize()
      .add(ForgeScript.createTextStimulus('+', 500)) // fixation
      .add(ForgeScript.createTextStimulus((context) => {
        const word = words[Math.floor(Math.random() * words.length)];
        const color = colors[Math.floor(Math.random() * colors.length)];
        return word;
      }, 0).color((context) => {
        return colors[Math.floor(Math.random() * colors.length)];
      }))
      .add(ForgeScript.createKeyboardResponse(['f', 'g', 'h'], 5000));

    // Thanks timeline
    const thanks = ForgeScript.createTimeline('thanks')
      .add(ForgeScript.createTextStimulus('Thank you for participating!', 3000));

    experiment.timeline([welcome, instructions, trialTimeline, thanks]);
    return experiment;
  },

  createSimpleRT: (stimuli: string[], trials: number = 50) => {
    const experiment = ForgeScript.createExperiment('Simple Reaction Time')
      .description('Simple reaction time task')
      .author('Generated by ForgeScript');

    const welcome = ForgeScript.createTimeline('welcome')
      .add(ForgeScript.createTextStimulus('Reaction Time Task', 2000))
      .add(ForgeScript.createTextStimulus('Press SPACE when you see a stimulus.\nPress SPACE to start.'))
      .add(ForgeScript.createKeyboardResponse(['space']));

    const trialTimeline = ForgeScript.createTimeline('trials')
      .repeat(trials)
      .add(ForgeScript.createWaitEvent(Math.random() * 2000 + 1000)) // random delay
      .add(ForgeScript.createTextStimulus((context) => {
        return stimuli[Math.floor(Math.random() * stimuli.length)];
      }))
      .add(ForgeScript.createKeyboardResponse(['space'], 5000));

    const thanks = ForgeScript.createTimeline('thanks')
      .add(ForgeScript.createTextStimulus('Task complete!', 2000));

    experiment.timeline([welcome, trialTimeline, thanks]);
    return experiment;
  }
};

// Default export
export default ForgeScript;

