/**
 * Enhanced Stroop Task using new FluentExperimentBuilder API
 * Demonstrates power analysis, type-safe conditions, and FZB compilation
 */

import { 
  experiment, 
  conditions, 
  trial,
  compileExperiment,
  type PowerAnalysisOptions 
} from '../src/index.js';

// Define our experimental conditions with type safety
interface StroopCondition {
  word: string;
  color: string;
  congruent: boolean;
}

async function createEnhancedStroopTask() {
  console.log('🧠 Creating Enhanced Stroop Task with Power Analysis...');

  // Configure power analysis for a medium effect size in an ANOVA
  const powerConfig: PowerAnalysisOptions = {
    effectSize: 0.5, // Medium effect size (Cohen's f)
    power: 0.8,      // 80% power
    alpha: 0.05,     // 5% significance level
    testType: 'anova',
    groups: 2,       // Congruent vs Incongruent
  };

  // Build experiment with fluent API and validation
  const experimentBuilder = experiment('enhanced-stroop-task')
    .title('Enhanced Stroop Task with Power Analysis')
    .description('Advanced Stroop task demonstrating type-safe conditions and power analysis')
    .version('2.0.0')
    .author('ForgeScript Team')
    .institution('Psycho-Forge Research Lab')
    .tags(['stroop', 'attention', 'cognitive-control', 'interference'])
    .requirePower(powerConfig)
    .backgroundColor('#f0f0f0')
    .fullScreen(true)
    .strict(true)           // Enable strict validation
    .optimize(true)         // Enable optimization
    .enableVerification(true); // Enable formal verification

  // Calculate required sample size
  const powerAnalysis = experimentBuilder.calculateSampleSize();
  console.log('📊 Power Analysis Results:');
  console.log(`  Required sample size: ${powerAnalysis.sampleSize}`);
  console.log(`  Statistical power: ${powerAnalysis.power}`);
  console.log(`  Effect size: ${powerAnalysis.effectSize}`);
  console.log(`  Recommendations:`);
  powerAnalysis.recommendations.forEach(rec => console.log(`    - ${rec}`));

  // Create type-safe experimental conditions
  const stroopConditions = conditions<StroopCondition>()
    .factor('word', ['RED', 'GREEN', 'BLUE', 'YELLOW'])
    .factor('color', ['red', 'green', 'blue', 'yellow'])
    .repeat(5) // 5 repetitions per condition
    .randomize(42) // Seeded randomization for reproducibility
    .build()
    .map(condition => ({
      ...condition,
      congruent: condition.word.toLowerCase() === condition.color
    }));

  console.log(`📝 Generated ${stroopConditions.length} trials`);
  console.log(`   Congruent trials: ${stroopConditions.filter(c => c.congruent).length}`);
  console.log(`   Incongruent trials: ${stroopConditions.filter(c => !c.congruent).length}`);

  // Create welcome timeline
  const welcomeTimeline = trial()
    .text('Welcome to the Enhanced Stroop Task!', 2000)
    .wait(500)
    .text('Press SPACE to continue')
    .keyboard(['space'])
    .build();

  // Create instruction timeline with detailed instructions
  const instructionTimeline = trial()
    .text(`Instructions:

You will see color words displayed in different colors.
Your task is to identify the COLOR of the text, not the word itself.

Response keys:
• Press 'R' for RED
• Press 'G' for GREEN  
• Press 'B' for BLUE
• Press 'Y' for YELLOW

Try to respond as quickly and accurately as possible.

Press SPACE when ready to begin.`, 8000)
    .keyboard(['space'])
    .build();

  // Create practice timeline
  const practiceTimeline = trial()
    .text('Practice Round', 1500)
    .wait(500)
    .fixation(500)
    .text('RED', 2000) // Practice with congruent
    .keyboard(['r', 'g', 'b', 'y'], 3000)
    .text('Good! Now for the real experiment.', 2000)
    .build();

  // Create main trial timeline using conditions
  const mainTrials = stroopConditions.map(condition => 
    trial<StroopCondition>()
      .setData('word', condition.word)
      .setData('color', condition.color)  
      .setData('congruent', condition.congruent)
      .setData('trial', condition._trial)
      .fixation(500)
      .text(condition.word, 0) // No duration limit - wait for response
      .keyboard(['r', 'g', 'b', 'y'], 5000) // 5 second timeout
      .wait(200) // Inter-trial interval
      .build()
  );

  // Create feedback timeline
  const feedbackTimeline = trial()
    .text('Task Complete!', 2000)
    .wait(500)
    .text('Thank you for participating in our research.', 3000)
    .build();

  // Add all timelines to experiment
  experimentBuilder
    .addTimeline(welcomeTimeline)
    .addTimeline(instructionTimeline)
    .addTimeline(practiceTimeline);

  // Add all main trials
  mainTrials.forEach(timeline => {
    experimentBuilder.addTimeline(timeline);
  });

  experimentBuilder.addTimeline(feedbackTimeline);

  // Validate experiment before compilation
  const validation = experimentBuilder.validate();
  if (!validation.valid) {
    console.error('❌ Experiment validation failed:');
    validation.errors.forEach(error => console.error(`  - ${error}`));
    return;
  }

  console.log('✅ Experiment validation passed');

  // Compile to FZB binary format
  console.log('🔧 Compiling to FZB binary format...');
  const compilationResult = await experimentBuilder.compile();

  if (compilationResult.success) {
    console.log('✨ Compilation successful!');
    console.log(`📦 Binary size: ${compilationResult.binary!.length} bytes`);
    console.log(`🏷️  Compiler version: ${compilationResult.metadata!.compilerVersion}`);
    console.log(`🔍 Source hash: ${compilationResult.metadata!.sourceHash}`);

    if (compilationResult.warnings.length > 0) {
      console.log('⚠️  Compilation warnings:');
      compilationResult.warnings.forEach(warning => 
        console.log(`  - ${warning.code}: ${warning.message}`)
      );
    }
  } else {
    console.error('❌ Compilation failed:');
    compilationResult.errors.forEach(error => 
      console.error(`  - ${error.code}: ${error.message}`)
    );
  }

  // Build the actual experiment object
  const experiment = experimentBuilder.build();

  console.log('🎯 Enhanced Stroop Task created successfully!');
  console.log(`   Title: ${experiment.getMetadata().title}`);
  console.log(`   Timelines: ${experiment.getTimelines().length}`);
  console.log(`   Expected duration: ~${Math.round(stroopConditions.length * 3)} seconds`);

  return {
    experiment,
    powerAnalysis,
    compilationResult,
    conditions: stroopConditions
  };
}

// Example usage with error handling
async function runExample() {
  try {
    const result = await createEnhancedStroopTask();

    if (result) {
      console.log('\n🚀 Enhanced Stroop Task ready for deployment!');

      // Example of how to save the compiled binary
      if (result.compilationResult.success && result.compilationResult.binary) {
        // In a real application, you would save this to a file or send to server
        const binaryData = result.compilationResult.binary;
        console.log(`💾 Binary ready for deployment (${binaryData.length} bytes)`);
      }
    }
  } catch (error) {
    console.error('❌ Failed to create Enhanced Stroop Task:', error);
  }
}

// Run the example if this file is executed directly
if (import.meta.url === `file://${process.argv[1]}`) {
  runExample();
}

export { createEnhancedStroopTask, runExample };

