/**
 * Tests for ForgeScript Compiler and FZB binary format
 */

import { describe, it, expect, beforeEach } from 'vitest';
import { 
  ForgeScriptCompiler, 
  compileExperiment, 
  decompileExperiment,
  experiment,
  trial
} from '../../src/index.js';

describe('ForgeScriptCompiler', () => {
  let compiler: ForgeScriptCompiler;
  let testExperiment: any;

  beforeEach(() => {
    compiler = new ForgeScriptCompiler();

    // Create a simple test experiment
    testExperiment = experiment('test-experiment')
      .title('Test Experiment')
      .version('1.0.0')
      .description('Test experiment for compiler validation')
      .addTimeline(
        trial()
          .text('Hello World', 1000)
          .keyboard(['space'])
          .build()
      )
      .build();
  });

  describe('Compilation', () => {
    it('should compile a valid experiment successfully', async () => {
      const result = await compiler.compile(testExperiment);

      expect(result.success).toBe(true);
      expect(result.binary).toBeDefined();
      expect(result.binary!.length).toBeGreaterThan(0);
      expect(result.metadata).toBeDefined();
      expect(result.errors).toHaveLength(0);
    });

    it('should include metadata in compilation result', async () => {
      const result = await compiler.compile(testExperiment);

      expect(result.metadata).toBeDefined();
      expect(result.metadata!.compilerVersion).toBe(ForgeScriptCompiler.getVersion());
      expect(result.metadata!.targetVersion).toBe('1.0.0');
      expect(result.metadata!.binarySize).toBe(result.binary!.length);
      expect(result.metadata!.sourceHash).toBeDefined();
    });

    it('should validate experiment during compilation', async () => {
      const result = await compiler.compile(testExperiment);

      expect(result.validation).toBeDefined();
      expect(result.validation.valid).toBe(true);
    });

    it('should fail compilation for invalid experiment in strict mode', async () => {
      const strictCompiler = new ForgeScriptCompiler({ strict: true });

      // Create invalid experiment (no timelines)
      const invalidExperiment = experiment('invalid')
        .title('') // Empty title should cause validation error
        .build();

      const result = await strictCompiler.compile(invalidExperiment);

      expect(result.success).toBe(false);
      expect(result.errors.length).toBeGreaterThan(0);
    });

    it('should handle compilation timeout', async () => {
      const timeoutCompiler = new ForgeScriptCompiler({ timeout: 1 }); // 1ms timeout

      const result = await timeoutCompiler.compile(testExperiment);

      // Should either succeed very quickly or timeout
      expect(result.success).toBe(false);
      expect(result.errors.some(e => e.message.includes('timeout'))).toBe(true);
    }, 10000); // 10 second test timeout
  });

  describe('FZB Binary Format', () => {
    it('should generate valid FZB binary', async () => {
      const result = await compiler.compile(testExperiment);

      expect(result.success).toBe(true);
      expect(ForgeScriptCompiler.isFZBFile(result.binary!)).toBe(true);
    });

    it('should detect non-FZB files', () => {
      const notFZB = new Uint8Array([0x00, 0x01, 0x02, 0x03]);
      expect(ForgeScriptCompiler.isFZBFile(notFZB)).toBe(false);
    });

    it('should handle empty binary', () => {
      const empty = new Uint8Array(0);
      expect(ForgeScriptCompiler.isFZBFile(empty)).toBe(false);
    });

    it('should handle partial magic bytes', () => {
      const partial = new Uint8Array([0x46, 0x5A]); // "FZ" but incomplete
      expect(ForgeScriptCompiler.isFZBFile(partial)).toBe(false);
    });
  });

  describe('Decompilation', () => {
    it('should decompile FZB binary back to experiment', async () => {
      // First compile
      const compileResult = await compiler.compile(testExperiment);
      expect(compileResult.success).toBe(true);

      // Then decompile
      const decompiled = await compiler.decompile(compileResult.binary!);

      expect(decompiled).toBeDefined();
      expect(decompiled.getMetadata().title).toBe('Test Experiment');
      expect(decompiled.getTimelines()).toHaveLength(1);
    });

    it('should fail to decompile invalid binary', async () => {
      const invalidBinary = new Uint8Array([0x00, 0x01, 0x02, 0x03]);

      await expect(compiler.decompile(invalidBinary)).rejects.toThrow();
    });

    it('should fail to decompile corrupted binary', async () => {
      // First compile a valid experiment
      const compileResult = await compiler.compile(testExperiment);
      expect(compileResult.success).toBe(true);

      // Corrupt the binary by changing some bytes
      const corrupted = new Uint8Array(compileResult.binary!);
      corrupted[10] = 0xFF; // Corrupt some data

      await expect(compiler.decompile(corrupted)).rejects.toThrow();
    });
  });

