/**
 * Tests for FluentExperimentBuilder and enhanced ForgeScript API
 */

import { describe, it, expect, beforeEach } from 'vitest';
import { 
  FluentExperimentBuilder, 
  experiment, 
  conditions, 
  trial,
  type PowerAnalysisOptions 
} from '../../src/index.js';

describe('FluentExperimentBuilder', () => {
  let builder: FluentExperimentBuilder;

  beforeEach(() => {
    builder = new FluentExperimentBuilder('test-experiment');
  });

  describe('Metadata Builder', () => {
    it('should set experiment title', () => {
      const result = builder.title('Test Title').build();
      expect(result.getMetadata().title).toBe('Test Title');
    });

    it('should validate title is not empty', () => {
      expect(() => builder.title('')).toThrow();
    });

    it('should set experiment description', () => {
      const result = builder.description('Test Description').build();
      expect(result.getMetadata().description).toBe('Test Description');
    });

    it('should validate semantic versioning', () => {
      expect(() => builder.version('1.0.0')).not.toThrow();
      expect(() => builder.version('invalid-version')).toThrow();
    });

    it('should set author and institution', () => {
      const result = builder
        .author('John Doe')
        .institution('Test University')
        .build();

      expect(result.getMetadata().author).toBe('John Doe');
      expect(result.getMetadata().institution).toBe('Test University');
    });

    it('should validate and set tags', () => {
      const result = builder.tags(['tag1', 'tag2', 'tag3']).build();
      expect(result.getMetadata().tags).toEqual(['tag1', 'tag2', 'tag3']);
    });

    it('should reject empty tags', () => {
      expect(() => builder.tags(['valid', ''])).toThrow();
    });
  });

  describe('Power Analysis', () => {
    it('should configure power analysis', () => {
      const powerOptions: PowerAnalysisOptions = {
        effectSize: 0.5,
        power: 0.8,
        alpha: 0.05,
        testType: 'ttest'
      };

      expect(() => builder.requirePower(powerOptions)).not.toThrow();
    });

    it('should validate power analysis options', () => {
      const invalidOptions = {
        effectSize: -0.5, // Invalid negative effect size
        testType: 'ttest'
      } as PowerAnalysisOptions;

      expect(() => builder.requirePower(invalidOptions)).toThrow();
    });

    it('should calculate sample size for t-test', () => {
      const powerOptions: PowerAnalysisOptions = {
        effectSize: 0.5,
        power: 0.8,
        alpha: 0.05,
        testType: 'ttest'
      };

      builder.requirePower(powerOptions);
      const result = builder.calculateSampleSize();

      expect(result.sampleSize).toBeGreaterThan(0);
      expect(result.power).toBe(0.8);
      expect(result.effectSize).toBe(0.5);
      expect(result.testConfig.testType).toBe('ttest');
    });

    it('should calculate sample size for ANOVA', () => {
      const powerOptions: PowerAnalysisOptions = {
        effectSize: 0.3,
        power: 0.9,
        alpha: 0.05,
        testType: 'anova',
        groups: 3
      };

      builder.requirePower(powerOptions);
      const result = builder.calculateSampleSize();

      expect(result.sampleSize).toBeGreaterThan(0);
      expect(result.testConfig.groups).toBe(3);
    });

    it('should provide recommendations based on analysis', () => {
      const powerOptions: PowerAnalysisOptions = {
        effectSize: 0.1, // Small effect size
        testType: 'ttest'
      };

      builder.requirePower(powerOptions);
      const result = builder.calculateSampleSize();

      expect(result.recommendations.length).toBeGreaterThan(0);
    });

    it('should throw error when calculating without power configuration', () => {
      expect(() => builder.calculateSampleSize()).toThrow();
    });
  });

  describe('Experiment Options', () => {
    it('should set fullscreen mode', () => {
      builder.fullScreen(true);
      // Would need to check internal state or build result
      expect(() => builder.build()).not.toThrow();
    });

    it('should validate background color', () => {
      expect(() => builder.backgroundColor('#ff0000')).not.toThrow();
      expect(() => builder.backgroundColor('red')).not.toThrow();
      expect(() => builder.backgroundColor('invalid-color')).toThrow();
    });

    it('should validate cursor type', () => {
      expect(() => builder.cursor('pointer')).not.toThrow();
      expect(() => builder.cursor('invalid-cursor')).toThrow();
    });
  });

  describe('Timeline Management', () => {
    it('should add timeline to experiment', () => {
      const timeline = trial()
        .text('Test', 1000)
        .keyboard(['space'])
        .build();

      const result = builder.addTimeline(timeline).build();
      expect(result.getTimelines()).toHaveLength(1);
    });

    it('should require at least one timeline', () => {
      expect(() => builder.build()).toThrow();
    });
  });

  describe('Validation', () => {
    it('should validate complete experiment', () => {
      const timeline = trial()
        .text('Test', 1000)
        .keyboard(['space'])
        .build();

      builder
        .title('Valid Experiment')
        .version('1.0.0')
        .addTimeline(timeline);

      const validation = builder.validate();
      expect(validation.valid).toBe(true);
      expect(validation.errors).toHaveLength(0);
    });

    it('should report validation errors', () => {
      // Missing title and timelines
      const validation = builder.validate();
      expect(validation.valid).toBe(false);
      expect(validation.errors.length).toBeGreaterThan(0);
    });
  });

  describe('Compiler Integration', () => {
    it('should compile experiment to FZB binary', async () => {
      const timeline = trial()
        .text('Test', 1000)
        .keyboard(['space'])
        .build();

      builder
        .title('Compilable Experiment')
        .version('1.0.0')
        .addTimeline(timeline)
        .strict(true)
        .optimize(true);

      const result = await builder.compile();
      expect(result.success).toBe(true);
      expect(result.binary).toBeDefined();
    });

    it('should handle compilation errors', async () => {
      // Create invalid experiment
      const result = await builder.compile();
      expect(result.success).toBe(false);
      expect(result.errors.length).toBeGreaterThan(0);
    });
  });

  describe('Preset Experiments', () => {
    it('should create Stroop task preset', () => {
      const stroopBuilder = FluentExperimentBuilder.stroopTask();
      expect(stroopBuilder.validate().valid).toBe(true);
    });

    it('should create simple RT preset', () => {
      const rtBuilder = FluentExperimentBuilder.simpleRT();
      expect(rtBuilder.validate().valid).toBe(true);
    });

    it('should create choice RT preset', () => {
      const choiceBuilder = FluentExperimentBuilder.choiceRT();
      expect(choiceBuilder.validate().valid).toBe(true);
    });
  });
});

describe('Convenience Functions', () => {
  describe('experiment()', () => {
    it('should create new experiment builder', () => {
      const builder = experiment('test');
      expect(builder).toBeInstanceOf(FluentExperimentBuilder);
    });
  });

  describe('conditions()', () => {
    it('should create condition builder', () => {
      const conditionBuilder = conditions<{ factor1: string; factor2: number }>();
      expect(conditionBuilder).toBeDefined();
    });
  });

  describe('trial()', () => {
    it('should create trial builder', () => {
      const trialBuilder = trial();
      expect(trialBuilder).toBeDefined();
    });
  });
});

describe('ConditionBuilder', () => {
  it('should create factorial design', () => {
    const result = conditions<{ word: string; color: string }>()
      .factor('word', ['red', 'blue'])
      .factor('color', ['red', 'blue'])
      .build();

    expect(result).toHaveLength(4);
    expect(result[0]).toMatchObject({ word: 'red', color: 'red' });
    expect(result[1]).toMatchObject({ word: 'red', color: 'blue' });
    expect(result[2]).toMatchObject({ word: 'blue', color: 'red' });
    expect(result[3]).toMatchObject({ word: 'blue', color: 'blue' });
  });

  it('should handle repeated conditions', () => {
    const result = conditions<{ stimulus: string }>()
      .factor('stimulus', ['A', 'B'])
      .repeat(3)
      .build();

    expect(result).toHaveLength(6);
    expect(result.filter(c => c.stimulus === 'A')).toHaveLength(3);
    expect(result.filter(c => c.stimulus === 'B')).toHaveLength(3);
  });

  it('should randomize conditions', () => {
    const result1 = conditions<{ item: number }>()
      .factor('item', [1, 2, 3, 4, 5])
      .randomize(42)
      .build();

    const result2 = conditions<{ item: number }>()
      .factor('item', [1, 2, 3, 4, 5])
      .randomize(42)
      .build();

    // Same seed should produce same order
    expect(result1.map(c => c.item)).toEqual(result2.map(c => c.item));
  });

  it('should apply blocking', () => {
    const result = conditions<{ block: string; item: number }>()
      .factor('block', ['A', 'B'])
      .factor('item', [1, 2])
      .block('block')
      .build();

    expect(result).toHaveLength(4);
    expect(result.filter(c => c.block === 'A')[0]._block).toBe(0);
    expect(result.filter(c => c.block === 'B')[0]._block).toBe(1);
  });

  it('should validate factor values', () => {
    expect(() => 
      conditions()
        .factor('empty', [])
        .build()
    ).toThrow();
  });

  it('should validate repeat count', () => {
    expect(() => 
      conditions()
        .factor('test', [1, 2])
        .repeat(0)
        .build()
    ).toThrow();
  });

  it('should require at least one factor', () => {
    expect(() => conditions().build()).toThrow();
  });
});

describe('TrialBuilder', () => {
  it('should create trial with fixation', () => {
    const timeline = trial()
      .fixation(1000, '+')
      .build();

    expect(timeline.getItems()).toHaveLength(1);
  });

  it('should create trial with text stimulus', () => {
    const timeline = trial()
      .text('Hello World', 2000)
      .build();

    expect(timeline.getItems()).toHaveLength(1);
  });

  it('should create trial with keyboard response', () => {
    const timeline = trial()
      .text('Press space')
      .keyboard(['space'], 5000)
      .build();

    expect(timeline.getItems()).toHaveLength(2);
  });

  it('should create trial with multiple stimuli', () => {
    const timeline = trial()
      .fixation(500)
      .text('Stimulus', 1000)
      .keyboard(['f', 'j'])
      .wait(200)
      .build();

    expect(timeline.getItems()).toHaveLength(4);
  });

  it('should support conditional logic', () => {
    const timeline = trial()
      .text('Test')
      .when(
        () => true,
        (builder) => builder.text('Conditional text')
      )
      .build();

    expect(timeline.getItems()).toHaveLength(2);
  });

  it('should support loops', () => {
    const timeline = trial()
      .loop(3, (builder) => {
        builder.text('Loop iteration');
      })
      .build();

    expect(timeline.getItems()).toHaveLength(1);
  });

  it('should support data setting', () => {
    const timeline = trial()
      .setData('condition', 'test')
      .setData('trial', 1)
      .text('Test')
      .build();

    expect(timeline.getItems()).toHaveLength(3);
  });

  it('should support different media types', () => {
    const timeline = trial()
      .image('test.jpg', 1000)
      .audio('test.wav')
      .video('test.mp4', 5000)
      .build();

    expect(timeline.getItems()).toHaveLength(3);
  });

  it('should support different response types', () => {
    const timeline = trial()
      .text('Choose response type')
      .mouse(3000)
      .touch(2000)
      .build();

    expect(timeline.getItems()).toHaveLength(3);
  });
});

