      expect(() => builder.backgroundColor('#ff0000')).not.toThrow();
      expect(() => builder.backgroundColor('red')).not.toThrow();
      expect(() => builder.backgroundColor('invalid-color')).toThrow();
    });

    it('should validate cursor type', () => {
      expect(() => builder.cursor('pointer')).not.toThrow();
      expect(() => builder.cursor('invalid-cursor')).toThrow();
    });
  });

  describe('Timeline Management', () => {
    it('should add timeline to experiment', () => {
      const timeline = trial()
        .text('Test', 1000)
        .keyboard(['space'])
        .build();

      const result = builder.addTimeline(timeline).build();
      expect(result.getTimelines()).toHaveLength(1);
    });

    it('should require at least one timeline', () => {
      expect(() => builder.build()).toThrow();
    });
  });

  describe('Validation', () => {
    it('should validate complete experiment', () => {
      const timeline = trial()
        .text('Test', 1000)
        .keyboard(['space'])
        .build();

      builder
        .title('Valid Experiment')
        .version('1.0.0')
        .addTimeline(timeline);

      const validation = builder.validate();
      expect(validation.valid).toBe(true);
      expect(validation.errors).toHaveLength(0);
    });

    it('should report validation errors', () => {
      // Missing title and timelines
      const validation = builder.validate();
      expect(validation.valid).toBe(false);
      expect(validation.errors.length).toBeGreaterThan(0);
    });
  });

  describe('Compiler Integration', () => {
    it('should compile experiment to FZB binary', async () => {
      const timeline = trial()
        .text('Test', 1000)
        .keyboard(['space'])
        .build();

      builder
        .title('Compilable Experiment')
        .version('1.0.0')
        .addTimeline(timeline)
        .strict(true)
        .optimize(true);

      const result = await builder.compile();
      expect(result.success).toBe(true);
      expect(result.binary).toBeDefined();
    });

    it('should handle compilation errors', async () => {
      // Create invalid experiment
      const result = await builder.compile();
      expect(result.success).toBe(false);
      expect(result.errors.length).toBeGreaterThan(0);
    });
  });

  describe('Preset Experiments', () => {
    it('should create Stroop task preset', () => {
      const stroopBuilder = FluentExperimentBuilder.stroopTask();
      expect(stroopBuilder.validate().valid).toBe(true);
    });

    it('should create simple RT preset', () => {
      const rtBuilder = FluentExperimentBuilder.simpleRT();
      expect(rtBuilder.validate().valid).toBe(true);
    });

    it('should create choice RT preset', () => {
      const choiceBuilder = FluentExperimentBuilder.choiceRT();
      expect(choiceBuilder.validate().valid).toBe(true);
    });
  });
});

