describe('ConditionBuilder', () => {
  it('should create factorial design', () => {
    const result = conditions<{ word: string; color: string }>()
      .factor('word', ['red', 'blue'])
      .factor('color', ['red', 'blue'])
      .build();

    expect(result).toHaveLength(4);
    expect(result[0]).toMatchObject({ word: 'red', color: 'red' });
    expect(result[1]).toMatchObject({ word: 'red', color: 'blue' });
    expect(result[2]).toMatchObject({ word: 'blue', color: 'red' });
    expect(result[3]).toMatchObject({ word: 'blue', color: 'blue' });
  });

  it('should handle repeated conditions', () => {
    const result = conditions<{ stimulus: string }>()
      .factor('stimulus', ['A', 'B'])
      .repeat(3)
      .build();

    expect(result).toHaveLength(6);
    expect(result.filter(c => c.stimulus === 'A')).toHaveLength(3);
    expect(result.filter(c => c.stimulus === 'B')).toHaveLength(3);
  });

  it('should randomize conditions', () => {
    const result1 = conditions<{ item: number }>()
      .factor('item', [1, 2, 3, 4, 5])
      .randomize(42)
      .build();

    const result2 = conditions<{ item: number }>()
      .factor('item', [1, 2, 3, 4, 5])
      .randomize(42)
      .build();

    // Same seed should produce same order
    expect(result1.map(c => c.item)).toEqual(result2.map(c => c.item));
  });

  it('should apply blocking', () => {
    const result = conditions<{ block: string; item: number }>()
      .factor('block', ['A', 'B'])
      .factor('item', [1, 2])
      .block('block')
      .build();

    expect(result).toHaveLength(4);
    expect(result.filter(c => c.block === 'A')[0]._block).toBe(0);
    expect(result.filter(c => c.block === 'B')[0]._block).toBe(1);
  });

  it('should validate factor values', () => {
    expect(() => 
      conditions()
        .factor('empty', [])
        .build()
    ).toThrow();
  });

  it('should validate repeat count', () => {
    expect(() => 
      conditions()
        .factor('test', [1, 2])
        .repeat(0)
        .build()
    ).toThrow();
  });

  it('should require at least one factor', () => {
    expect(() => conditions().build()).toThrow();
  });
});

describe('TrialBuilder', () => {
  it('should create trial with fixation', () => {
    const timeline = trial()
      .fixation(1000, '+')
      .build();

    expect(timeline.getItems()).toHaveLength(1);
  });

  it('should create trial with text stimulus', () => {
    const timeline = trial()
      .text('Hello World', 2000)
      .build();

    expect(timeline.getItems()).toHaveLength(1);
  });

  it('should create trial with keyboard response', () => {
    const timeline = trial()
      .text('Press space')
      .keyboard(['space'], 5000)
      .build();

    expect(timeline.getItems()).toHaveLength(2);
  });

  it('should create trial with multiple stimuli', () => {
    const timeline = trial()
      .fixation(500)
      .text('Stimulus', 1000)
      .keyboard(['f', 'j'])
      .wait(200)
      .build();

    expect(timeline.getItems()).toHaveLength(4);
  });

  it('should support conditional logic', () => {
    const timeline = trial()
      .text('Test')
      .when(
        () => true,
        (builder) => builder.text('Conditional text')
      )
      .build();

    expect(timeline.getItems()).toHaveLength(2);
  });

  it('should support loops', () => {
    const timeline = trial()
      .loop(3, (builder) => {
        builder.text('Loop iteration');
      })
      .build();

    expect(timeline.getItems()).toHaveLength(1);
  });

  it('should support data setting', () => {
    const timeline = trial()
      .setData('condition', 'test')
      .setData('trial', 1)
      .text('Test')
      .build();

    expect(timeline.getItems()).toHaveLength(3);
  });

  it('should support different media types', () => {
    const timeline = trial()
      .image('test.jpg', 1000)
      .audio('test.wav')
      .video('test.mp4', 5000)
      .build();

    expect(timeline.getItems()).toHaveLength(3);
  });

  it('should support different response types', () => {
    const timeline = trial()
      .text('Choose response type')
      .mouse(3000)
      .touch(2000)
      .build();

    expect(timeline.getItems()).toHaveLength(3);
  });
});
